import type { BottomTabScreenProps } from '@react-navigation/bottom-tabs'
import type { CompositeScreenProps } from '@react-navigation/core'
import type { StackScreenProps } from '@react-navigation/stack'
import { useCallback, useEffect, useState } from 'react'
import { ErrorBoundary } from 'react-error-boundary'
import { View, useWindowDimensions } from 'react-native'
import { useTheme } from 'react-native-paper'
import type { Route, SceneRendererProps, NavigationState } from 'react-native-tab-view'
import { TabView, TabBar } from 'react-native-tab-view'

import ErrorFallback from '../components/ErrorFallback'
import { RetailersFilter } from '../components/RetailersFilter'
import { StoresList } from '../components/StoresList'
import StoresMap from '../components/StoresMap'
import { Copies } from '../constants'
import type { HomeTabsParamList, RootStackParamList } from '../navigation/types'
import { useAppSelector } from '../redux'
import type { Coords } from '../redux/types'
import { useGetNearbyStoresAndRetailersQuery } from '../utils/api'
import type { RetailerFilter } from '../utils/api/types'
import { useStyles } from '../utils/useStyles'

export type StoresScreenProps = CompositeScreenProps<
  BottomTabScreenProps<HomeTabsParamList, 'Stores', 'HomeTabs'>,
  StackScreenProps<RootStackParamList>
>

const StoresScreen = ({ route, navigation }: StoresScreenProps) => {
  const layout = useWindowDimensions()
  const { countryCode } = route.params
  const location = useAppSelector((state) => state.app.location)
  const [coords, setCoords] = useState<Coords>()
  const [index, setIndex] = useState(0)
  const [routes] = useState([
    { key: 'list', title: Copies.list },
    { key: 'map', title: Copies.map },
  ])
  const { data = { stores: [], retailers: [] }, error } = useGetNearbyStoresAndRetailersQuery(
    {
      countryCode,
      nearbyOptions: coords!,
    },
    { skip: !coords },
  )
  const { colors } = useTheme()
  const [filteredStores, setFilteredStores] = useState(data.stores)

  const styles = useStyles(
    ({ colors }) => ({
      tabBar: {
        backgroundColor: colors.background,
      },
      tabBarIndicator: {
        backgroundColor: colors.primaryContainer,
      },
    }),
    [],
  )

  useEffect(() => {
    setCoords({ latitude: location.latitude, longitude: location.longitude })
  }, [location.latitude, location.longitude])

  if (error) {
    // TODO: handle error?
    throw new Error(JSON.stringify(error))
  }

  const handleOnSearchRequest = useCallback((coords: Coords) => {
    setCoords(coords)
  }, [])

  const handleRenderScene = useCallback(
    ({ route }: { route: Route }) => {
      switch (route.key) {
        case 'list':
          return (
            <StoresList
              verticalFlat
              stores={filteredStores.length > 0 ? filteredStores : data.stores}
            />
          )
        case 'map':
          return (
            <StoresMap
              initialCoords={{ latitude: location.latitude, longitude: location.longitude }}
              stores={filteredStores.length > 0 ? filteredStores : data.stores}
              onSearchRequest={(coords) => handleOnSearchRequest(coords)}
            />
          )
        default:
          return null
      }
    },
    [data.stores, filteredStores, handleOnSearchRequest, location.latitude, location.longitude],
  )

  const handleOnChange = useCallback(
    (retailers: RetailerFilter['id'][]) => {
      const newStores = data.stores.filter((store) =>
        retailers.some((id) => id === store.retailer_id),
      )
      newStores && setFilteredStores(newStores)
    },
    [data.stores],
  )

  const handleRenderTabBar = useCallback(
    (props: SceneRendererProps & { navigationState: NavigationState<Route> }) => {
      return (
        <View>
          <TabBar
            // eslint-disable-next-line react/jsx-props-no-spreading
            {...props}
            indicatorStyle={styles.tabBarIndicator}
            style={styles.tabBar}
            activeColor={colors.onBackground}
            inactiveColor={colors.onBackground}
          />
          <RetailersFilter onChange={handleOnChange} retailers={data.retailers} />
        </View>
      )
    },
    [colors.onBackground, data.retailers, handleOnChange, styles.tabBar, styles.tabBarIndicator],
  )

  return (
    <ErrorBoundary FallbackComponent={ErrorFallback}>
      <TabView
        navigationState={{ index, routes }}
        renderScene={handleRenderScene}
        onIndexChange={setIndex}
        initialLayout={{ width: layout.width }}
        renderTabBar={handleRenderTabBar}
        lazy
      />
    </ErrorBoundary>
  )
}

export default StoresScreen
