import { Suspense, lazy, useEffect } from 'react'
import { ActivityIndicator } from 'react-native-paper'

import type { CatalogueViewerProps } from './types'

const CatalogueViewerReactPdf = lazy(() => import('./CatalogueViewerReactPdf.web'))
const CatalogueViewerSwiper = lazy(() => import('./CatalogueViewerSwiper.web'))

export const CatalogueViewer = ({ webViewer, ...props }: CatalogueViewerProps) => {
  useEffect(() => {
    document.body.style.overflow = 'hidden'
    return () => {
      document.body.style.overflow = 'auto'
    }
  }, [])

  return webViewer === 'react-pdv-viewer' ? (
    <Suspense fallback={<ActivityIndicator size="large" />}>
      {/* eslint-disable-next-line react/jsx-props-no-spreading */}
      <CatalogueViewerReactPdf {...props} />
    </Suspense>
  ) : (
    <Suspense fallback={<ActivityIndicator size="large" />}>
      {/* eslint-disable-next-line react/jsx-props-no-spreading */}
      <CatalogueViewerSwiper {...props} />
    </Suspense>
  )
}

export default CatalogueViewer
