import { useCallback } from 'react'
import type { ListRenderItem } from 'react-native'
import { StyleSheet, FlatList, View, Platform } from 'react-native'

import { SpacingBase } from '../../constants'
import useBreakpointsValue from '../../utils/useBreakpointsValue'
import { CatalogueCardPlaceholder } from '../CatalogueCard'

export interface CataloguePlaceholder {
  _hasAdNext: boolean
}

export interface CataloguesGridPlaceholderProps {
  items: CataloguePlaceholder[]
}

const styles = StyleSheet.create({
  row: {
    paddingRight: SpacingBase * 2,
    marginBottom: SpacingBase * 2,
  },
  item: {
    flex: 1,
    marginLeft: SpacingBase * 2,
  },
  adSeparator: {
    marginLeft: SpacingBase * 2,
    marginBottom: SpacingBase * 2,
    paddingRight: SpacingBase * 2,
    alignItems: 'center',
    height: 100, // height of the LARGE_BANNER
  },
})

export const CataloguesGridPlaceholder = ({ items }: CataloguesGridPlaceholderProps) => {
  const numColumns =
    (useBreakpointsValue({ xs: 2, sm: 3, md: 4, lg: 5, xl: 6, xxl: 7 }) as number) || 2

  const renderItem: ListRenderItem<unknown> = useCallback(() => {
    return (
      <View style={styles.item}>
        <CatalogueCardPlaceholder />
      </View>
    )
  }, [])

  const AdSeparator = ({ leadingItem }: { leadingItem: CataloguePlaceholder[] }) => {
    return leadingItem[1]._hasAdNext ? <View style={styles.adSeparator} /> : null
  }

  return (
    <FlatList
      numColumns={numColumns}
      key={numColumns}
      data={items}
      renderItem={renderItem}
      columnWrapperStyle={styles.row}
      ItemSeparatorComponent={Platform.OS !== 'web' ? AdSeparator : undefined}
    />
  )
}

export default CataloguesGridPlaceholder
