import { useCallback, useState } from 'react'
import { Platform, StyleSheet, View } from 'react-native'
import { Divider, FAB, Menu } from 'react-native-paper'

import { SpacingBase } from '../../constants'

export interface CatalogueViewerSettingsProps {
  onDirectionSwitch: () => void
  onViewerSwitch: () => void
  viewerType: 'react-pdv-viewer' | 'swiper'
}

const styles = StyleSheet.create({
  main: {
    position: 'absolute',
    right: SpacingBase * 3,
    bottom: SpacingBase * 3,
  },
})

export const CatalogueViewerSettings = ({
  onDirectionSwitch,
  onViewerSwitch,
  viewerType,
}: CatalogueViewerSettingsProps) => {
  const [visible, setVisible] = useState(false)
  const [horizontal, setHorizontal] = useState(false)

  const handleOnOpen = useCallback(() => {
    setVisible(true)
  }, [])
  const handleOnClose = useCallback(() => {
    setVisible(false)
  }, [])

  const handleDirectionSwitch = useCallback(() => {
    handleOnClose()
    setHorizontal(!horizontal)
    onDirectionSwitch()
  }, [horizontal, onDirectionSwitch, handleOnClose])

  const handleViewerSwitch = useCallback(() => {
    handleOnClose()
    onViewerSwitch()
  }, [onViewerSwitch, handleOnClose])

  return (
    <View style={styles.main}>
      <Menu
        visible={visible}
        onDismiss={handleOnClose}
        anchor={<FAB size="small" icon="cog" onPress={handleOnOpen} />}
      >
        <Menu.Item
          leadingIcon={horizontal ? 'pan-vertical' : 'pan-horizontal'}
          onPress={handleDirectionSwitch}
          title={horizontal ? 'Vertical Swipe' : 'Horizontal Swiper'}
        />
        {Platform.OS === 'web' && (
          <>
            <Divider />
            <Menu.Item
              leadingIcon="paper-roll"
              onPress={handleViewerSwitch}
              title={
                viewerType === 'react-pdv-viewer'
                  ? 'Switch to swiper + react-pdf'
                  : 'Switch to react-pdf-viewer'
              }
            />
          </>
        )}
      </Menu>
    </View>
  )
}

export default CatalogueViewerSettings
