import { createApi, fakeBaseQuery } from '@reduxjs/toolkit/query/react'
import { addDays } from 'date-fns'

import type { BaseArgs, Catalogue, Store, RetailerFilter } from './types'
import type { Coords } from '../../redux/types'
import enrichCatalogue from '../enrichCatalogue'
import enrichStore from '../enrichStore'
import supabaseClient from '../supabaseClient'
import capitalizeString from '../text/capitalizeString'

const catalogueFields =
  'country, date_end, date_start, dist_meters, id, pdf_url, thumb_url, title, retailers(*)'

const storeFields =
  'country, address, city, dist_meters, id, location, name, province, retailer_id, retailer_name, retailer_slug, website_url, zipcode, latitude, longitude'

const today = new Date()

export const supabaseApi = createApi({
  reducerPath: 'supabaseApi',
  baseQuery: fakeBaseQuery(),
  endpoints: (builder) => ({
    getNearbyCataloguesWithAds: builder.query<
      { catalogues: Catalogue[]; retailers: RetailerFilter[] },
      BaseArgs & { nearbyOptions: Coords }
    >({
      queryFn: async ({ countryCode, nearbyOptions }) => {
        const country = countryCode.toUpperCase()
        const { data, error } = await supabaseClient
          .rpc('nearby_catalogues', {
            distance: parseInt(process.env.EXPO_PUBLIC_DISTANCE_QUERY ?? '30000', 10),
            lat: nearbyOptions.latitude,
            long: nearbyOptions.longitude,
          })
          .eq('country', country)
          .lt('date_start', addDays(today, 3).toISOString()) // TODO: remote config?
          .gt('date_end', new Date().toISOString())
          .select(catalogueFields)
          .limit(parseInt(process.env.EXPO_PUBLIC_CATALOGUES_LIST_LIMIT ?? '30000', 10))

        if (error) {
          return { error }
        }

        const enrichedData: {
          catalogues: Catalogue[]
          retailers: RetailerFilter[]
        } = { catalogues: [], retailers: [] }

        data.forEach((catalogue, index) => {
          const enrichedCatalogue = enrichCatalogue(catalogue)

          if (index === 1 || (index - 2) % 4 === 3) {
            enrichedData.catalogues.push({ ...enrichedCatalogue, _hasAdNext: true })
          } else {
            enrichedData.catalogues.push(enrichedCatalogue)
          }

          const existingRetailer = enrichedData.retailers.find(
            (r) => r.id === enrichedCatalogue._retailer_id,
          )
          if (!existingRetailer) {
            enrichedData.retailers.push({
              id: enrichedCatalogue._retailer_id,
              name: capitalizeString(enrichedCatalogue._retailer_name),
              slug: enrichedCatalogue._retailer_slug,
            })
          }
        })

        return { data: enrichedData }
      },
    }),
    getCataloguesByIds: builder.query<Catalogue[], BaseArgs & { ids: string[] }>({
      queryFn: async ({ countryCode, ids }) => {
        const country = countryCode.toUpperCase()
        const { data, error } = await supabaseClient
          .from('catalogues')
          .select(catalogueFields)
          .eq('country', country)
          .in('id', ids)
        if (error) {
          return { error }
        }

        const enrichedData = data.map((catalogue) => enrichCatalogue(catalogue))
        return { data: enrichedData }
      },
    }),
    getStoresByIds: builder.query<Store[], BaseArgs & { ids: string[] }>({
      queryFn: async ({ countryCode, ids }) => {
        const country = countryCode.toUpperCase()
        const { data, error } = await supabaseClient
          .from('stores')
          .select(storeFields)
          .eq('country', country)
          .in('id', ids)
        if (error) {
          return { error }
        }

        const enrichedData = data.map((store) => enrichStore(store))
        return { data: enrichedData }
      },
    }),
    getNearbyStoresAndRetailers: builder.query<
      { stores: Store[]; retailers: RetailerFilter[] },
      BaseArgs & { nearbyOptions: Coords }
    >({
      queryFn: async ({ countryCode, nearbyOptions }) => {
        const country = countryCode.toUpperCase()
        const { data, error } = await supabaseClient
          .rpc('nearby_stores', {
            distance: parseInt(process.env.EXPO_PUBLIC_DISTANCE_QUERY ?? '30000', 10),
            lat: nearbyOptions.latitude,
            long: nearbyOptions.longitude,
          })
          .eq('country', country)
          .select(storeFields)
          .limit(parseInt(process.env.EXPO_PUBLIC_STORES_LIST_LIMIT ?? '50', 10))
        if (error) {
          return { error }
        }

        const enrichedData: {
          stores: Store[]
          retailers: RetailerFilter[]
        } = { stores: [], retailers: [] }

        data.forEach((store) => {
          enrichedData.stores.push(enrichStore(store))
          if (!store.retailer_id || !store.retailer_name || !store.retailer_slug) {
            return
          }
          const existingRetailer = enrichedData.retailers.find((r) => r.id === store.retailer_id)
          if (!existingRetailer) {
            enrichedData.retailers.push({
              id: store.retailer_id,
              name: capitalizeString(store.retailer_name),
              slug: store.retailer_slug,
            })
          }
        })

        return { data: enrichedData }
      },
    }),
    getNearbyStoresByCatalogueId: builder.query<
      Store[],
      BaseArgs & { nearbyOptions: Coords; id: string }
    >({
      queryFn: async ({ countryCode, id, nearbyOptions }) => {
        const country = countryCode.toUpperCase()
        const { data, error } = await supabaseClient
          .rpc('nearby_stores', {
            distance: parseInt(process.env.EXPO_PUBLIC_DISTANCE_QUERY ?? '30000', 10),
            lat: nearbyOptions.latitude,
            long: nearbyOptions.longitude,
          })
          .eq('country', country)
          .eq('catalogues.id', id)
          .select(`${storeFields}, catalogues!inner(id)`)
        if (error) {
          return { error }
        }

        const enrichedData = data.map((store) => enrichStore(store))
        return { data: enrichedData }
      },
    }),
  }),
})

export const {
  useGetNearbyCataloguesWithAdsQuery,
  useGetCataloguesByIdsQuery,
  useGetNearbyStoresByCatalogueIdQuery,
  useGetNearbyStoresAndRetailersQuery,
  useGetStoresByIdsQuery,
} = supabaseApi
