import { ActivityIndicator, Card } from 'react-native-paper'

import { SpacingBase } from '../../constants'
import { useStyles } from '../../utils/useStyles'

export interface StoreCardPlaceholderProps {
  flat?: boolean
}

export const StoreCardPlaceholder = ({ flat }: StoreCardPlaceholderProps) => {
  const styles = useStyles(
    ({ colors, roundness }) => ({
      contentStyle: {
        height: flat ? 120 : 122,
        justifyContent: 'center',
        backgroundColor: flat ? colors.elevation.level0 : colors.elevation.level1,
        borderRadius: flat ? 0 : roundness * 3,
        borderWidth: flat ? 0 : 1,
        borderColor: colors.outlineVariant,
      },
    }),
    [flat],
  )

  return (
    <Card elevation={0} contentStyle={styles.contentStyle}>
      <ActivityIndicator size={SpacingBase * 4} />
    </Card>
  )
}

export default StoreCardPlaceholder
