/* eslint-disable camelcase */

import type { QueriedStore, Store } from './api/types'
import capitalizeString from './text/capitalizeString'
import formatDistanceNumber from './text/formatDistanceNumber'

const enrichStore = (s: QueriedStore): Store => {
  return {
    ...s,
    city: s.city ? capitalizeString(s.city) : s.city,
    address: s.address ? capitalizeString(s.address) : s.address,
    retailer_name: s.retailer_name ? capitalizeString(s.retailer_name) : s.retailer_name,
    _distance: s.dist_meters && s.dist_meters >= 0 ? formatDistanceNumber(s.dist_meters) : '',
  }
}

export default enrichStore
