import { Fragment, useCallback, useState } from 'react'
import type { ListRenderItem, ListRenderItemInfo } from 'react-native'
import { StyleSheet, View } from 'react-native'
import { FlatList } from 'react-native-gesture-handler'
import { Text } from 'react-native-paper'

import RetailersFilterItem from './RetailersFilterItem'
import { Copies, SpacingBase } from '../../constants'
import type { RetailerFilter } from '../../utils/api/types'

export interface RetailersFilterProps {
  retailers: RetailerFilter[]
  onChange: (retailers: RetailerFilter['id'][]) => void
}

const styles = StyleSheet.create({
  title: {
    padding: SpacingBase * 2,
  },
  contentContainer: {
    paddingLeft: SpacingBase * 2,
    paddingBottom: SpacingBase * 2,
    alignItems: 'center',
  },
  itemContainer: {
    marginRight: SpacingBase,
  },
})

export const RetailersFilter = ({ retailers, onChange }: RetailersFilterProps) => {
  const [filteredRetailers, setFilteredRetailers] = useState<RetailerFilter['id'][]>([])

  const handleOnRetailerPress = useCallback(
    (id: RetailerFilter['id'], selected: boolean) => {
      if (selected) {
        const newRetailers = filteredRetailers.filter((retailerId) => id !== retailerId)
        setFilteredRetailers(newRetailers)
        onChange(newRetailers)
      } else {
        setFilteredRetailers([...filteredRetailers, id])
        onChange([...filteredRetailers, id])
      }
    },
    [filteredRetailers, onChange],
  )

  // const handleOnDeleteFilters = useCallback(() => {
  //   setFilteredRetailers([])
  //   onChange([])
  // }, [onChange])

  const handleRenderRetailer: ListRenderItem<RetailerFilter> = useCallback(
    ({ item, index }: ListRenderItemInfo<RetailerFilter>) => {
      const selected = filteredRetailers.some((id) => item.id === id)
      return (
        <View style={styles.itemContainer}>
          <RetailersFilterItem
            retailer={item}
            selected={selected}
            onPress={() => handleOnRetailerPress(item.id, selected)}
          />
        </View>
      )
    },
    [filteredRetailers, handleOnRetailerPress],
  )

  return (
    <>
      <Text style={styles.title} variant="labelMedium">
        {Copies.filter_by_retailer}
      </Text>
      {/* {filteredRetailers.length > 0 && (
        <Chip
          selectedColor={colors.onError}
          style={{ backgroundColor: colors.error }}
          onClose={handleOnDeleteFilters}
          onPress={handleOnDeleteFilters}
        >
          {Copies.delete}
        </Chip>
      )} */}
      <FlatList
        data={retailers}
        renderItem={handleRenderRetailer}
        keyExtractor={(item) => item.id}
        horizontal
        ListEmptyComponent={<View style={{ height: SpacingBase * 4 }} />}
        contentContainerStyle={styles.contentContainer}
      />
    </>
  )
}

export default RetailersFilter
