/* eslint-disable camelcase */
import type { Route } from '@react-navigation/native'
import { initializeAnalytics, logEvent } from 'firebase/analytics'

import createScreenName from './createScreenName'
import firebaseApp from './firebaseApp.web'
import type { CitySlug, CountryCode } from '../../navigation/types'

const analytics = initializeAnalytics(firebaseApp, { config: { send_page_view: false } })

export const logScreenView = async ({ name, path, params = {} }: Route<string>) => {
  const { countryCode, citySlug }: Readonly<{ countryCode?: CountryCode; citySlug?: CitySlug }> =
    params

  // eslint-disable-next-line @typescript-eslint/await-thenable
  await logEvent(analytics, 'page_view', {
    // @ts-expect-error: generic route is not typed
    page_title: createScreenName(name, params),
    // FIXME: route path is undefined except the first route in state
    page_path: path ?? window.location.pathname,
    page_location: window.location.href,
    country_code: countryCode,
    city_slug: citySlug,
  })
}
