import type { PayloadAction } from '@reduxjs/toolkit'
import { createAction, createSlice } from '@reduxjs/toolkit'
import type { AppStateStatus } from 'react-native'
import { AppState as NativeAppState } from 'react-native'

import type { Location } from './types'
import { DefaultLocations } from '../constants'
import type { CitySlug, CountryCode } from '../navigation/types'
import storage, { storageKeys } from '../utils/storage'

export interface AppState {
  status: AppStateStatus
  user_onboard: boolean
  countryCode: CountryCode
  citySlug: CitySlug | null
  location: Location
  favourite_catalogues: string[]
  favourite_stores: string[]
}

const getInitialLocation = () => {
  const storedLocation = storage.getString(storageKeys.location)
  if (storedLocation) {
    return JSON.parse(storedLocation) as Location
  } else {
    return DefaultLocations[process.env.EXPO_PUBLIC_DEFAULT_COUNTRY_CODE as CountryCode]
  }
}

const getInitialFavCatalogues = () => {
  const storedFavs = storage.getString(storageKeys.favourite_catalogues)
  if (storedFavs) {
    return JSON.parse(storedFavs) as string[]
  } else {
    return []
  }
}

const getInitialFavStores = () => {
  const storedFavs = storage.getString(storageKeys.favourite_stores)
  if (storedFavs) {
    return JSON.parse(storedFavs) as string[]
  } else {
    return []
  }
}

const initialState: AppState = {
  status: NativeAppState.currentState,
  user_onboard: storage.getBoolean(storageKeys.user_onboard) ?? false,
  countryCode: process.env.EXPO_PUBLIC_DEFAULT_COUNTRY_CODE as CountryCode,
  citySlug: null,
  location: getInitialLocation(),
  favourite_catalogues: getInitialFavCatalogues(),
  favourite_stores: getInitialFavStores(),
}

export const setUserOnboard = createAction(
  'app/setUserOnboard',
  (value: AppState['user_onboard']) => {
    storage.set(storageKeys.user_onboard, value)
    return { payload: value }
  },
)

export const setLocation = createAction('app/setLocation', (value: Location) => {
  storage.set(storageKeys.location, JSON.stringify(value))
  return { payload: value }
})

export const setDefaultLocation = createAction(
  'app/setDefaultLocation',
  (countryCode: CountryCode) => {
    const { latitude, longitude, display } = DefaultLocations[countryCode]
    storage.set(storageKeys.location, JSON.stringify({ latitude, longitude, display }))
    return { payload: { latitude, longitude, display } }
  },
)

export const setCitySlug = createAction('app/setCitySlug', (value: string) => {
  storage.set(storageKeys.citySlug, value)
  return { payload: value }
})

export const deleteCitySlug = createAction('app/deleteCitySlug', () => {
  storage.delete(storageKeys.citySlug)
  return { payload: null }
})

export const setFavouriteCatalogue = createAction('app/setFavouriteCatalogue', (value: string) => {
  const storedFavs = storage.getString(storageKeys.favourite_catalogues)
  const favs = storedFavs ? (JSON.parse(storedFavs) as string[]) : []
  favs.push(value)
  storage.set(storageKeys.favourite_catalogues, JSON.stringify(favs))
  return { payload: favs }
})

export const deleteFavouriteCatalogue = createAction(
  'app/deleteFavouriteCatalogue',
  (value: string) => {
    const storedFavs = storage.getString(storageKeys.favourite_catalogues)
    const favs = storedFavs ? (JSON.parse(storedFavs) as string[]) : []
    const newFavs = favs.filter((fav) => fav !== value)
    storage.set(storageKeys.favourite_catalogues, JSON.stringify(newFavs))
    return { payload: newFavs }
  },
)

export const setFavouriteStore = createAction('app/setFavouriteStore', (value: string) => {
  const storedFavs = storage.getString(storageKeys.favourite_stores)
  const favs = storedFavs ? (JSON.parse(storedFavs) as string[]) : []
  favs.push(value)
  storage.set(storageKeys.favourite_stores, JSON.stringify(favs))
  return { payload: favs }
})

export const deleteFavouriteStore = createAction('app/deleteFavouriteStore', (value: string) => {
  const storedFavs = storage.getString(storageKeys.favourite_stores)
  const favs = storedFavs ? (JSON.parse(storedFavs) as string[]) : []
  const newFavs = favs.filter((fav) => fav !== value)
  storage.set(storageKeys.favourite_stores, JSON.stringify(newFavs))
  return { payload: newFavs }
})

export const emptyFavouriteCatalogues = createAction('app/emptyFavouriteCatalogues', () => {
  storage.set(storageKeys.favourite_catalogues, JSON.stringify([]))
  return { payload: [] }
})

export const emptyFavouriteStores = createAction('app/emptyFavouriteStores', () => {
  storage.set(storageKeys.favourite_stores, JSON.stringify([]))
  return { payload: [] }
})

export const appSlice = createSlice({
  name: 'app',
  initialState,
  reducers: {
    setAppStatus: (state, action: PayloadAction<AppStateStatus>) => {
      state.status = action.payload
    },
    setCountryCode: (state, action: PayloadAction<CountryCode>) => {
      state.countryCode = action.payload
    },
  },
  extraReducers: (builder) => {
    builder.addCase(setUserOnboard, (state, action) => {
      state.user_onboard = action.payload
    })
    builder.addCase(setLocation, (state, action) => {
      state.location = action.payload
    })
    builder.addCase(setDefaultLocation, (state, action) => {
      state.location = action.payload
    })
    builder.addCase(setCitySlug, (state, action) => {
      state.citySlug = action.payload
    })
    builder.addCase(deleteCitySlug, (state, action) => {
      state.citySlug = action.payload
    })
    builder.addCase(setFavouriteCatalogue, (state, action) => {
      state.favourite_catalogues = action.payload
    })
    builder.addCase(deleteFavouriteCatalogue, (state, action) => {
      state.favourite_catalogues = action.payload
    })
    builder.addCase(emptyFavouriteCatalogues, (state, action) => {
      state.favourite_catalogues = action.payload
    })
    builder.addCase(setFavouriteStore, (state, action) => {
      state.favourite_stores = action.payload
    })
    builder.addCase(deleteFavouriteStore, (state, action) => {
      state.favourite_stores = action.payload
    })
    builder.addCase(emptyFavouriteStores, (state, action) => {
      state.favourite_stores = action.payload
    })
  },
})

export const { setAppStatus, setCountryCode } = appSlice.actions
export default appSlice
