import { memo } from 'react'
import type { ListRenderItemInfo } from 'react-native'

import type { CountryCode } from '../../navigation/types'
import type { Catalogue } from '../../utils/api/types'
import { CatalogueCard } from '../CatalogueCard'
import HeadPreloadImg from '../HeadPreloadImg'

export interface CataloguesListItemProps {
  item: ListRenderItemInfo<Catalogue>['item']
  index: ListRenderItemInfo<Catalogue>['index']
  countryCode: CountryCode
}

export const CataloguesListItem = memo(
  ({ item, index, countryCode }: CataloguesListItemProps) => {
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    const imgUrl = item.thumb_url ?? (require('../../assets/images/adaptive-icon.png') as string)
    return (
      <>
        {index <= 1 && <HeadPreloadImg imgUrl={imgUrl} imgType="image/webp" />}
        <CatalogueCard
          title={item.title ?? ''}
          expiration={item._expiration_label}
          retailer={item._retailer_name}
          distance={item._distance}
          urgencyLevel={item._expiration_urgency_level}
          linkParams={{ countryCode, id: item.id! }}
          imgSource={imgUrl}
        />
      </>
    )
  },
  (prevProps, nextProps) => {
    return prevProps.index === nextProps.index
  },
)

export default CataloguesListItem
