import { createApi, fakeBaseQuery } from '@reduxjs/toolkit/query/react'

import type { BaseArgs, City } from './types'

type CitiesList = Record<string, City[]>
// eslint-disable-next-line global-require, @typescript-eslint/no-var-requires, @typescript-eslint/no-unsafe-assignment
const citiesList: CitiesList = require('../mocks/cities.json')

export const fakeApi = createApi({
  reducerPath: 'fakeApi',
  baseQuery: fakeBaseQuery(),
  endpoints: (builder) => ({
    getCities: builder.query<City[], BaseArgs>({
      queryFn: ({ countryCode }) => {
        const data = citiesList[countryCode]
        return {
          data: data.slice().sort((a, b) => {
            return a.name.localeCompare(b.name)
          }),
        }
      },
    }),
    getCityBySlug: builder.query<City[], BaseArgs>({
      queryFn: ({ citySlug, countryCode }) => {
        const data = citiesList[countryCode].find((city) => city.slug === citySlug)
        if (!data) {
          return { error: { message: `city '${citySlug}' not found`, code: '404' } }
        }
        return { data: [data] }
      },
    }),
  }),
})

export const { useGetCityBySlugQuery, useGetCitiesQuery } = fakeApi
