import { createStackNavigator } from '@react-navigation/stack'
import { useMemo } from 'react'
import { Platform } from 'react-native'

import HomeTabs from './HomeTabs'
import type { RootStackParamList } from './types'
import Header from '../components/Header'
import { useAppSelector } from '../redux'
import CatalogueDetailScreen from '../screens/CatalogueDetailScreen'
import GeoScreen from '../screens/GeoScreen'
import NotFoundScreen from '../screens/NotFoundScreen'
import OnBoardingScreen from '../screens/OnboardingScreen'

const Stack = createStackNavigator<RootStackParamList>()

export const RootStack = () => {
  const { countryCode, citySlug, user_onboard } = useAppSelector((state) => state.app)

  // TODO: avoid ternary when bug will be fixed:
  // - https://github.com/react-navigation/react-navigation/issues/8671
  // - https://github.com/react-navigation/react-navigation/issues/7909
  const initialParams = useMemo(
    () => (citySlug ? { countryCode, citySlug } : { countryCode }),
    [citySlug, countryCode],
  )

  return (
    <Stack.Navigator
      id="RootStack"
      screenOptions={{
        headerMode: 'screen',
        // eslint-disable-next-line react/jsx-props-no-spreading
        header: (props) => <Header {...props} />,
      }}
      initialRouteName={Platform.select({
        native: user_onboard ? 'HomeTabs' : 'Onboarding',
        web: 'HomeTabs',
      })}
    >
      <Stack.Screen name="Onboarding" component={OnBoardingScreen} initialParams={initialParams} />
      <Stack.Screen name="HomeTabs" component={HomeTabs} />
      <Stack.Screen name="CatalogueDetail" component={CatalogueDetailScreen} />
      <Stack.Screen name="Geo" component={GeoScreen} />
      <Stack.Screen name="NotFound" component={NotFoundScreen} />
    </Stack.Navigator>
  )
}

export default RootStack
