import 'react-native-gesture-handler'
import { useReduxDevToolsExtension } from '@react-navigation/devtools'
import type { Route, Theme } from '@react-navigation/native'
import { NavigationContainer, useNavigationContainerRef } from '@react-navigation/native'
import * as Linking from 'expo-linking'
import { useCallback, useRef } from 'react'

import type { RootStackParamList, CountryCode, CitySlug } from './types'
import { deleteCitySlug, setCitySlug, setCountryCode, setLocation, useAppDispatch } from '../redux'
import { fakeApi } from '../utils/api'
import { logScreenView } from '../utils/firebase'

export interface NavigationProviderProps {
  theme: Theme
  children: React.JSX.Element
}

export const NavigationProvider = ({ theme, children }: NavigationProviderProps) => {
  const navigationRef = useNavigationContainerRef<RootStackParamList>()
  const routeRef = useRef<Route<string> | undefined>()
  const dispatch = useAppDispatch()

  useReduxDevToolsExtension(navigationRef)

  const prefix = Linking.createURL('/')
  const linking = {
    prefixes: ['https://milloo.me', prefix],
    config: {
      screens: {
        HomeTabs: {
          screens: {
            Catalogues: '/:countryCode/:citySlug?',
            Stores: '/:countryCode/:citySlug?/stores',
            ForYou: '/:countryCode/:citySlug?/for-you',
          },
        },
        CatalogueDetail: {
          path: '/:countryCode/catalogues/:id/:pageNumber?',
          parse: {
            pageNumber: Number,
          },
        },
        Geo: '/:countryCode/:citySlug?/location',
        NotFound: '*',
      },
    },
  }

  const handleCitySlug = useCallback(
    (countryCode: CountryCode, citySlug: CitySlug) => {
      dispatch(fakeApi.endpoints.getCityBySlug.initiate({ countryCode, citySlug }))
        .then(({ data }) => {
          if (data) {
            dispatch(
              setLocation({
                latitude: parseFloat(data[0].lat),
                longitude: parseFloat(data[0].lng),
                display: data[0].name,
              }),
            )
            dispatch(setCitySlug(citySlug))
          } else {
            // wrong slug
            dispatch(deleteCitySlug())
            navigationRef.navigate('HomeTabs', { screen: 'Catalogues', params: { countryCode } })
          }
        })
        // api error
        .catch(() => {
          dispatch(deleteCitySlug())
          navigationRef.navigate('HomeTabs', { screen: 'Catalogues', params: { countryCode } })
        })
    },
    [dispatch, navigationRef],
  )

  const handleOnReady = useCallback(async () => {
    routeRef.current = navigationRef.getCurrentRoute()

    if (routeRef.current) {
      await logScreenView(routeRef.current)

      // TODO: handle missing or wrong countryCode
      // @ts-expect-error: https://reactnavigation.org/docs/typescript/#annotating-useroute
      const { countryCode, citySlug }: { countryCode: CountryCode; citySlug?: CitySlug } =
        routeRef.current.params

      dispatch(setCountryCode(countryCode))

      if (citySlug) {
        handleCitySlug(countryCode, citySlug)
      } else {
        dispatch(deleteCitySlug())
      }
    }
  }, [dispatch, handleCitySlug, navigationRef])

  const handleOnStateChange = useCallback(async () => {
    const previousRoute = routeRef.current
    const currentRoute = navigationRef.getCurrentRoute()

    if (previousRoute?.key !== currentRoute?.key) {
      // Save the current route for later comparison
      routeRef.current = currentRoute

      if (currentRoute) {
        await logScreenView(currentRoute)

        // @ts-expect-error: https://reactnavigation.org/docs/typescript/#annotating-useroute
        const { citySlug, countryCode }: { countryCode: CountryCode; citySlug?: CitySlug } =
          currentRoute.params

        if (citySlug) {
          handleCitySlug(countryCode, citySlug)
        } else {
          dispatch(deleteCitySlug())
        }
      }
    }
  }, [dispatch, handleCitySlug, navigationRef])

  return (
    <NavigationContainer
      linking={linking}
      theme={theme}
      ref={navigationRef}
      onReady={handleOnReady}
      onStateChange={handleOnStateChange}
    >
      {children}
    </NavigationContainer>
  )
}
export default NavigationProvider
