import { createBottomTabNavigator } from '@react-navigation/bottom-tabs'
import { CommonActions } from '@react-navigation/native'
import type { StackScreenProps } from '@react-navigation/stack'
import { useEffect, useMemo } from 'react'
import { Platform } from 'react-native'
import { BottomNavigation, Icon } from 'react-native-paper'

import type { HomeTabsParamList, RootStackParamList } from './types'
import { Copies } from '../constants'
import { useAppSelector } from '../redux'
import CataloguesScreen from '../screens/CataloguesScreen'
import ForYouScreen from '../screens/ForYouScreen'
import StoresScreen from '../screens/StoresScreen'

export type HomeTabsProps = StackScreenProps<RootStackParamList, 'HomeTabs', 'RootStack'>

const Tab = createBottomTabNavigator<HomeTabsParamList>()

const HomeTabs = ({ navigation, route }: HomeTabsProps) => {
  const { countryCode, citySlug } = useAppSelector((state) => state.app)

  // TODO: avoid ternary when bug will be fixed:
  // - https://github.com/react-navigation/react-navigation/issues/8671
  // - https://github.com/react-navigation/react-navigation/issues/7909
  const initialParams = useMemo(
    () => (citySlug ? { countryCode, citySlug } : { countryCode }),
    [citySlug, countryCode],
  )

  return (
    <Tab.Navigator
      id="HomeTabs"
      screenOptions={{
        headerShown: false,
        lazy: Platform.select({
          native: false,
          web: true,
        }),
      }}
      tabBar={({ navigation, state, descriptors, insets }) => (
        <BottomNavigation.Bar
          navigationState={state}
          safeAreaInsets={insets}
          onTabPress={({ route, preventDefault }) => {
            const event = navigation.emit({
              type: 'tabPress',
              target: route.key,
              canPreventDefault: true,
            })

            if (event.defaultPrevented) {
              preventDefault()
            } else {
              navigation.dispatch({
                ...CommonActions.navigate(route.name, route.params),
                target: state.key,
              })
            }
          }}
          renderIcon={({ route, focused, color }) => {
            const { options } = descriptors[route.key]
            if (options.tabBarIcon) {
              return options.tabBarIcon({ focused, color, size: 24 })
            }

            return null
          }}
          getLabelText={({ route }) => {
            const { options } = descriptors[route.key]
            const label =
              typeof options.tabBarLabel === 'string'
                ? options.tabBarLabel
                : options.title ?? route.name
            return label
          }}
        />
      )}
    >
      <Tab.Screen
        name="Catalogues"
        component={CataloguesScreen}
        initialParams={initialParams}
        options={{
          tabBarLabel: Copies.catalogues,
          tabBarIcon: ({ color, size }) => {
            return <Icon source="newspaper-variant-multiple" size={size} color={color} />
          },
        }}
      />
      <Tab.Screen
        name="Stores"
        component={StoresScreen}
        initialParams={initialParams}
        options={{
          tabBarLabel: Copies.stores,
          tabBarIcon: ({ color, size }) => {
            return <Icon source="store" size={size} color={color} />
          },
        }}
      />
      <Tab.Screen
        name="ForYou"
        component={ForYouScreen}
        initialParams={initialParams}
        options={{
          tabBarLabel: Copies.for_you,
          tabBarIcon: ({ color, size }) => {
            return <Icon source="star" size={size} color={color} />
          },
        }}
      />
    </Tab.Navigator>
  )
}

export default HomeTabs
