import { Chip } from 'react-native-paper'

import type { RetailerFilter } from '../../utils/api/types'
import { useStyles } from '../../utils/useStyles'

export interface RetailersFilterItemProps {
  retailer: RetailerFilter
  selected: boolean
  onPress: () => void
}

const RetailersFilterItem = ({ onPress, retailer, selected }: RetailersFilterItemProps) => {
  const styles = useStyles(
    ({ colors }) => ({
      main: {
        backgroundColor: selected ? colors.secondaryContainer : colors.surfaceVariant,
      },
      text: {
        color: selected ? colors.onSecondaryContainer : colors.onSurface,
      },
    }),
    [selected],
  )

  return (
    <Chip
      showSelectedCheck
      compact
      selected={selected}
      style={styles.main}
      textStyle={styles.text}
      onPress={onPress}
    >
      {retailer.name}
    </Chip>
  )
}

export default RetailersFilterItem
