import { useCallback } from 'react'
import type { FlatListProps, ListRenderItem, ListRenderItemInfo } from 'react-native'
import { View } from 'react-native'
import { FlatList } from 'react-native-gesture-handler'
import { Divider } from 'react-native-paper'

import StoresListItem from './StoresListItem'
import { SpacingBase } from '../../constants'
import type { Store } from '../../utils/api/types'
import { useStyles } from '../../utils/useStyles'
import { StoreCardPlaceholder } from '../StoreCard'

export interface StoresListProps {
  stores: Store[]
  contentContainerStyle?: FlatListProps<Store>['contentContainerStyle']
  verticalFlat?: boolean
}

const ListEmptyComponent = ({ style, flat }: { style: object; flat?: boolean }) => {
  return Array.from({
    length: 20,
  }).map((_, index) => (
    <View key={index} style={style}>
      <StoreCardPlaceholder flat={flat} />
    </View>
  ))
}

export const StoresList = ({ stores, contentContainerStyle, verticalFlat }: StoresListProps) => {
  const styles = useStyles(
    () => ({
      storesList: {
        paddingBottom: verticalFlat ? 0 : SpacingBase * 2, // for the item shadow
      },
      storesItem: {
        marginRight: verticalFlat ? 0 : SpacingBase * 2,
        width: verticalFlat ? 'auto' : 300,
      },
    }),
    [verticalFlat],
  )

  const handleRenderItem: ListRenderItem<Store> = useCallback(
    ({ item, index }: ListRenderItemInfo<Store>) => {
      return (
        <View style={styles.storesItem}>
          <StoresListItem flat={verticalFlat} store={item} />
        </View>
      )
    },
    [styles.storesItem, verticalFlat],
  )

  return (
    <FlatList
      keyExtractor={(item) => item.id!}
      data={stores}
      renderItem={handleRenderItem}
      horizontal={!verticalFlat}
      ItemSeparatorComponent={verticalFlat ? Divider : null}
      ListEmptyComponent={<ListEmptyComponent style={styles.storesItem} flat={verticalFlat} />}
      contentContainerStyle={[styles.storesList, contentContainerStyle]}
    />
  )
}

export default StoresList
