import { memo } from 'react'

import type { Store } from '../../utils/api/types'
import { StoreCard } from '../StoreCard'

export interface StoresListItemProps {
  store: Store
  flat?: boolean
}

export const StoresListItem = memo(
  ({ store, flat }: StoresListItemProps) => {
    return (
      <StoreCard
        id={store.id}
        address={store.address}
        city={store.city}
        retailer={store.retailer_name}
        distance={store._distance}
        flat={flat}
      />
    )
  },
  (prevProps, nextProps) => {
    return prevProps.store.id === nextProps.store.id
  },
)

export default StoresListItem
