/* eslint-disable camelcase */
import { Platform } from 'react-native'
import { MMKV } from 'react-native-mmkv'

export const storageKeys = {
  location: 'location',
  favourite_catalogues: 'favourite_catalogues',
  favourite_stores: 'favourite_stores',
  user_onboard: 'user_onboard',
  citySlug: 'citySlug',
  theme: 'theme',
}

const storageId = process.env.EXPO_PUBLIC_STORAGE_ID ?? false
const encryptionKey = process.env.EXPO_PUBLIC_STORAGE_ENCRYPTIONKEY ?? false

if (!storageId || !encryptionKey) {
  throw new Error('missing storage')
}

const storage = new MMKV(
  Platform.select({
    native: {
      id: storageId,
      encryptionKey,
    },
  }),
)

export default storage
