import type { BottomTabScreenProps } from '@react-navigation/bottom-tabs'
import type { CompositeScreenProps } from '@react-navigation/native'
import type { StackScreenProps } from '@react-navigation/stack'
import { useCallback } from 'react'
import { ErrorBoundary } from 'react-error-boundary'
import { ScrollView, StyleSheet, View } from 'react-native'
import { Divider, Icon, List } from 'react-native-paper'

import { CataloguesList } from '../components/CataloguesList'
import EmptyFavList from '../components/EmptyFavList'
import ErrorFallback from '../components/ErrorFallback'
import { StoresList } from '../components/StoresList'
import { Copies, SpacingBase } from '../constants'
import type { HomeTabsParamList, RootStackParamList } from '../navigation/types'
import { setTheme, showPrivacyOptionsForm, useAppDispatch, useAppSelector } from '../redux'
import { useGetCataloguesByIdsQuery, useGetStoresByIdsQuery } from '../utils/api'
import type { Catalogue, Store } from '../utils/api/types'

export type ForYouScreenProps = CompositeScreenProps<
  BottomTabScreenProps<HomeTabsParamList, 'ForYou', 'HomeTabs'>,
  StackScreenProps<RootStackParamList>
>

const styles = StyleSheet.create({
  listContainer: {
    paddingLeft: SpacingBase * 2,
  },
  placehoderStores: {
    height: 138,
    justifyContent: 'center',
    paddingLeft: SpacingBase * 2,
    paddingRight: SpacingBase * 2,
  },
  placehoderCatalogues: {
    height: 321,
    justifyContent: 'center',
    paddingLeft: SpacingBase * 2,
    paddingRight: SpacingBase * 2,
  },
})

const StoresOrPlaceholder = ({ isLoading, stores }: { isLoading: boolean; stores: Store[] }) => {
  return isLoading || stores.length > 0 ? (
    <StoresList contentContainerStyle={styles.listContainer} stores={stores} />
  ) : (
    <View style={styles.placehoderStores}>
      <EmptyFavList type="stores" />
    </View>
  )
}

const CataloguesOrPlaceholder = ({
  isLoading,
  catalogues,
}: {
  isLoading: boolean
  catalogues: Catalogue[]
}) => {
  return isLoading || catalogues.length > 0 ? (
    <CataloguesList contentContainerStyle={styles.listContainer} catalogues={catalogues} />
  ) : (
    <View style={styles.placehoderCatalogues}>
      <EmptyFavList type="catalogues" />
    </View>
  )
}

const ForYouScreen = ({ route, navigation }: ForYouScreenProps) => {
  const { countryCode } = route.params
  const { favourite_catalogues, favourite_stores } = useAppSelector((state) => state.app)
  const theme = useAppSelector((state) => state.ui.theme)
  const dispatch = useAppDispatch()
  const {
    data: catalogues = [],
    error: cataloguesError,
    isLoading: isLoadingCatalogues,
  } = useGetCataloguesByIdsQuery({
    countryCode,
    ids: favourite_catalogues,
  })
  const {
    data: stores = [],
    error: storesError,
    isLoading: isLoadingStores,
  } = useGetStoresByIdsQuery({
    countryCode,
    ids: favourite_stores,
  })

  if (cataloguesError || storesError) {
    // TODO: handle error?
    throw new Error(JSON.stringify(cataloguesError || storesError))
  }

  const handleOnSwitchTheme = useCallback(() => {
    dispatch(setTheme(theme === 'dark' ? 'light' : 'dark'))
  }, [dispatch, theme])

  const handleOnConsentForm = useCallback(async () => {
    await dispatch(showPrivacyOptionsForm())
  }, [dispatch])

  return (
    <ErrorBoundary FallbackComponent={ErrorFallback}>
      <ScrollView>
        <List.Section title={Copies.your_favourites_stores}>
          <StoresOrPlaceholder isLoading={isLoadingStores} stores={stores} />
        </List.Section>
        <Divider />
        <List.Section title={Copies.your_favourites_catalogues}>
          <CataloguesOrPlaceholder isLoading={isLoadingCatalogues} catalogues={catalogues} />
        </List.Section>
        <Divider />
        <List.Section title={Copies.settings}>
          <List.Item
            onPress={handleOnSwitchTheme}
            title={Copies.toggle_theme}
            right={() => <Icon size={SpacingBase * 3} source="theme-light-dark" />}
          />
          <List.Item
            onPress={handleOnConsentForm}
            title={Copies.consent_form}
            right={() => <Icon size={SpacingBase * 3} source="eye-outline" />}
          />
        </List.Section>
      </ScrollView>
    </ErrorBoundary>
  )
}

export default ForYouScreen
