/* eslint-disable camelcase */
import { addDays, parseISO, format, formatDistanceToNowStrict, differenceInDays } from 'date-fns'
import { it } from 'date-fns/locale'

import type { Catalogue, QueriedCatalogue, expirationUrgencyLevel } from './api/types'
import capitalizeString from './text/capitalizeString'
import cleanString from './text/cleanString'
import formatDistanceNumber from './text/formatDistanceNumber'
import { Copies } from '../constants'

export const getDateInfo = (iso_date_start: string, iso_date_end: string) => {
  const { ends_on, ends_in, expired, expires_today, starts_in } = Copies

  const today = new Date()

  const date_start = parseISO(iso_date_start)
  // we add 1 day to date_end in order to manage midnight time:
  // for example: 2023-12-26T00:00:00+00:00 means the date_end includes 2023-12-26
  const date_end = addDays(parseISO(iso_date_end), 1)
  const daysDiffFromStart = differenceInDays(date_start, today)
  const distanceFromStart = formatDistanceToNowStrict(date_start, { locale: it })

  const daysDiffFromEnd = differenceInDays(date_end, today)
  const distanceFromEnd = formatDistanceToNowStrict(date_end, { locale: it })

  let dateInfo: {
    _expiration_label: Catalogue['_expiration_label']
    _expiration_urgency_level: Catalogue['_expiration_urgency_level']
  }

  if (daysDiffFromEnd < 0) {
    dateInfo = { _expiration_label: expired, _expiration_urgency_level: 100 }
  } else if (daysDiffFromEnd === 0) {
    dateInfo = { _expiration_label: expires_today, _expiration_urgency_level: 2 }
  } else if (daysDiffFromEnd < 3) {
    dateInfo = { _expiration_label: `${ends_in} ${distanceFromEnd}`, _expiration_urgency_level: 2 }
  } else if (daysDiffFromEnd <= 10) {
    dateInfo = { _expiration_label: `${ends_in} ${distanceFromEnd}`, _expiration_urgency_level: 1 }
  } else {
    dateInfo = {
      _expiration_label: `${ends_on} ${format(date_end, 'dd/MM', { locale: it })}`,
      _expiration_urgency_level: 0,
    }
  }

  if (daysDiffFromStart > 0) {
    dateInfo = {
      _expiration_label: `${starts_in} ${distanceFromStart}`,
      _expiration_urgency_level: -1,
    }
  }

  return dateInfo
}

const enrichCatalogue = (c: QueriedCatalogue): Catalogue => {
  let expirationLabel = c.date_end ?? ''
  let urgencyLevel: expirationUrgencyLevel = 0

  if (c.date_start && c.date_end) {
    const { _expiration_label, _expiration_urgency_level } = getDateInfo(c.date_start, c.date_end)
    expirationLabel = _expiration_label
    urgencyLevel = _expiration_urgency_level
  }

  return {
    ...c,
    title: c.title ? capitalizeString(cleanString(c.title)) : c.title,
    _retailer_name:
      c.retailers.length > 0 && c.retailers[0].name ? capitalizeString(c.retailers[0].name) : '',
    _retailer_id: c.retailers.length > 0 && c.retailers[0].id ? c.retailers[0].id : '',
    _retailer_slug: c.retailers.length > 0 && c.retailers[0].slug ? c.retailers[0].slug : '',
    _distance: c.dist_meters && c.dist_meters >= 0 ? formatDistanceNumber(c.dist_meters) : '',
    _expiration_label: expirationLabel,
    _expiration_urgency_level: urgencyLevel,
  }
}

export default enrichCatalogue
