import { Icon, List } from 'react-native-paper'

import { Copies, SpacingBase } from '../../constants'
import type { Store } from '../../utils/api/types'
import { useStyles } from '../../utils/useStyles'
import { StoresList } from '../StoresList'

export interface CatalogueSheetProps {
  contentColor?: string
  onFavourite: () => void
  onChangeDirection: () => void
  isFavourite: boolean
  isHorizontal: boolean
  stores: Store[]
}

export const CatalogueSheet = ({
  contentColor,
  onFavourite,
  onChangeDirection,
  isFavourite,
  isHorizontal,
  stores,
}: CatalogueSheetProps) => {
  const { add_to_favoutites, remove_from_favourites, swipe_horizontally, swipe_vertically } = Copies

  const styles = useStyles(
    () => ({
      storesContainer: {
        paddingLeft: SpacingBase * 2,
      },
      listItem: {
        paddingLeft: SpacingBase * 2,
        paddingRight: SpacingBase * 2,
      },
      title: {
        color: contentColor,
      },
    }),
    [contentColor],
  )

  return (
    <>
      {stores.length > 0 && (
        <>
          <List.Subheader>{Copies.stores}</List.Subheader>
          <StoresList stores={stores} contentContainerStyle={styles.storesContainer} />
        </>
      )}
      <List.Section title={Copies.catalogue}>
        <List.Item
          // eslint-disable-next-line camelcase
          title={isFavourite ? remove_from_favourites : add_to_favoutites}
          left={() => (
            <Icon
              color={contentColor}
              source={isFavourite ? 'star' : 'star-outline'}
              size={SpacingBase * 3}
            />
          )}
          onPress={onFavourite}
          style={styles.listItem}
          titleStyle={styles.title}
        />
        <List.Item
          // eslint-disable-next-line camelcase
          title={isHorizontal ? swipe_vertically : swipe_horizontally}
          left={() => (
            <Icon
              color={contentColor}
              source={isHorizontal ? 'pan-vertical' : 'pan-horizontal'}
              size={SpacingBase * 3}
            />
          )}
          onPress={onChangeDirection}
          style={styles.listItem}
          titleStyle={styles.title}
        />
      </List.Section>
    </>
  )
}

export default CatalogueSheet
