import type { StackHeaderProps, StackScreenProps } from '@react-navigation/stack'
import { useCallback, useEffect, useMemo, useState } from 'react'
import { ErrorBoundary } from 'react-error-boundary'
import { Platform, StyleSheet, View } from 'react-native'
import { ActivityIndicator, Appbar, useTheme } from 'react-native-paper'

import { BottomSheet, CatalogueSheet } from '../components/BottomSheets'
import { CatalogueViewer } from '../components/CatalogueViewer'
import ErrorFallback from '../components/ErrorFallback'
import Header from '../components/Header'
import { BottomSheetHandleHeight, Copies, ExtraColors, SpacingBase } from '../constants'
import type { RootStackParamList } from '../navigation/types'
import {
  deleteFavouriteCatalogue,
  setFavouriteCatalogue,
  useAppDispatch,
  useAppSelector,
} from '../redux'
import { useGetCataloguesByIdsQuery, useGetNearbyStoresByCatalogueIdQuery } from '../utils/api'
import type { Catalogue } from '../utils/api/types'

export type CatalogueDetailScreenProps = StackScreenProps<
  RootStackParamList,
  'CatalogueDetail',
  'RootStack'
>

const styles = StyleSheet.create({
  main: {
    flex: 1,
    justifyContent: 'center',
  },
})

const CatalogueDetailScreen = ({ route, navigation }: CatalogueDetailScreenProps) => {
  const [catalogue, setCatalogue] = useState<Catalogue | null>(null)
  const [viewerType] = useState<'react-pdv-viewer' | 'swiper'>('swiper')
  const [horizontal, setHorizontal] = useState(false)
  const { id, countryCode, pageNumber = 1 } = route.params
  const [initialPageNumber] = useState(pageNumber)
  const uri = useMemo(() => catalogue?.pdf_url, [catalogue?.pdf_url])
  const { location, favourite_catalogues } = useAppSelector((state) => state.app)
  const isFav = useMemo(
    () => (catalogue?.id ? favourite_catalogues.includes(catalogue.id) : false),
    [catalogue, favourite_catalogues],
  )
  const dispatch = useAppDispatch()
  const { colors } = useTheme()

  const {
    data: catalogues,
    error,
    isLoading,
  } = useGetCataloguesByIdsQuery({ countryCode, ids: [id] })

  const { data: stores = [] } = useGetNearbyStoresByCatalogueIdQuery(
    {
      countryCode,
      id,
      nearbyOptions: { latitude: location.latitude, longitude: location.longitude },
    },
    { skip: !catalogue },
  )

  if (error) {
    // TODO: handle error?
    throw new Error(JSON.stringify(error))
  }

  const handleOnPressFav = useCallback(() => {
    if (!catalogue) {
      return
    }
    if (isFav) {
      dispatch(deleteFavouriteCatalogue(catalogue.id!))
    } else {
      dispatch(setFavouriteCatalogue(catalogue.id!))
    }
  }, [catalogue, dispatch, isFav])

  const renderHeader = useCallback(
    (props: StackHeaderProps) => {
      return (
        // eslint-disable-next-line react/jsx-props-no-spreading
        <Header {...props}>
          <Appbar.Action
            size={SpacingBase * 4}
            onPress={handleOnPressFav}
            color={ExtraColors.gold}
            icon={isFav ? 'star' : 'star-outline'}
          />
        </Header>
      )
    },
    [handleOnPressFav, isFav],
  )

  useEffect(() => {
    if (catalogues) {
      setCatalogue(catalogues[0])
      navigation.setOptions({
        header: renderHeader,
      })
    }
  }, [catalogues, navigation, renderHeader])

  const handleOnPageChanged = useCallback(
    (page: number, numberOfPages: number) => {
      navigation.setParams({ pageNumber: page })
      navigation.setOptions({
        // title: `${catalogue?.retailer_name} - ${page} / ${numberOfPages}`,
        headerTitle: Copies.getPageOf(page.toString(), numberOfPages.toString()),
      })
    },
    [navigation],
  )

  // const handleOnViewerSwitch = useCallback(() => {
  //   setViewerType(viewerType === 'react-pdv-viewer' ? 'swiper' : 'react-pdv-viewer')
  // }, [viewerType])

  const handleOnChangeDirection = useCallback(() => {
    setHorizontal(!horizontal)
  }, [horizontal])

  return (
    <ErrorBoundary FallbackComponent={ErrorFallback}>
      {isLoading || !catalogue ? (
        <View style={styles.main}>
          <ActivityIndicator size="large" />
        </View>
      ) : (
        uri && (
          <CatalogueViewer
            horizontal={horizontal}
            onPageChanged={handleOnPageChanged}
            page={initialPageNumber}
            uri={uri}
            webViewer={viewerType}
          />
        )
      )}
      {Platform.OS !== 'web' && (
        <BottomSheet
          backgroundColor={colors.surfaceVariant}
          snapPoints={
            stores.length > 0
              ? [BottomSheetHandleHeight * 1.5, 380]
              : [BottomSheetHandleHeight * 1.5, 200]
          }
          handleComponentText={Copies.stores_and_settings}
        >
          <CatalogueSheet
            stores={stores}
            contentColor={colors.onSurfaceVariant}
            onChangeDirection={handleOnChangeDirection}
            onFavourite={handleOnPressFav}
            isFavourite={isFav}
            isHorizontal={horizontal}
          />
        </BottomSheet>
      )}
    </ErrorBoundary>
  )
}

export default CatalogueDetailScreen
