import { useNavigation } from '@react-navigation/native'
import { useCallback } from 'react'
import { Button, useTheme } from 'react-native-paper'

import { Copies } from '../../constants'
import { useAppSelector } from '../../redux'

export const GeoAction = () => {
  const { countryCode, citySlug, location } = useAppSelector((state) => state.app)
  const { colors } = useTheme()
  const navigation = useNavigation()

  const handleOnPress = useCallback(() => {
    navigation.navigate('Geo', citySlug ? { countryCode, citySlug } : { countryCode })
  }, [citySlug, countryCode, navigation])

  return (
    <Button
      mode="contained"
      buttonColor={colors.primaryContainer}
      textColor={colors.onPrimaryContainer}
      onPress={handleOnPress}
      icon="map-search-outline"
    >
      {Copies.you_are_here}: {location.display}
    </Button>
  )
}

export default GeoAction
