import {
  requestForegroundPermissionsAsync,
  PermissionStatus,
  getCurrentPositionAsync,
} from 'expo-location'
import { useCallback, useState } from 'react'
import { Button, useTheme } from 'react-native-paper'

import { Copies } from '../../constants'
import { setLocation, useAppDispatch } from '../../redux'
import { nominatimApi } from '../../utils/api'
import type { NomReverseResultAddress } from '../../utils/api/types'

export interface GeoLocationButtonProps {
  onLocationRetrieved?: () => void
}

export const GeoLocationButton = ({ onLocationRetrieved }: GeoLocationButtonProps) => {
  const { colors } = useTheme()
  const dispatch = useAppDispatch()
  const [isLoadingLocation, setIsLoadingLocation] = useState(false)

  const handleSetLocationDisplay = useCallback((data: NomReverseResultAddress) => {
    const { road, quarter, city, town } = data
    let firstPart = ''
    let secondPart = ''
    if (road) {
      firstPart = `${road}, `
    } else if (quarter) {
      firstPart = `${quarter}, `
    }
    if (city) {
      secondPart = city
    } else if (town) {
      secondPart = town
    }
    return firstPart + secondPart
  }, [])

  const handleOnRetrieveLocationPress = useCallback(async () => {
    setIsLoadingLocation(true)

    const { status } = await requestForegroundPermissionsAsync()
    if (status !== PermissionStatus.GRANTED) {
      setIsLoadingLocation(false)
      return
    }

    const {
      coords: { latitude, longitude },
    } = await getCurrentPositionAsync()

    dispatch(nominatimApi.endpoints.nomReverse.initiate({ latitude, longitude }))
      .then(({ data }) => {
        dispatch(
          setLocation({
            latitude,
            longitude,
            display: data ? handleSetLocationDisplay(data) : `${latitude}, ${longitude}`,
          }),
        )
        setIsLoadingLocation(false)
        onLocationRetrieved && onLocationRetrieved()
      })
      .catch((e) => {
        // TODO: handle error on UI
        console.error(e)
        setIsLoadingLocation(false)
        onLocationRetrieved && onLocationRetrieved()
      })
  }, [dispatch, handleSetLocationDisplay, onLocationRetrieved])

  // TODO: handle location permission denied
  return (
    <Button
      loading={isLoadingLocation}
      onPress={handleOnRetrieveLocationPress}
      icon="map-marker-account"
      mode="elevated"
      buttonColor={colors.primaryContainer}
      textColor={colors.onPrimaryContainer}
    >
      {Copies.use_your_location}
    </Button>
  )
}

export default GeoLocationButton
