import { getFocusedRouteNameFromRoute } from '@react-navigation/native'
import type { StackHeaderProps } from '@react-navigation/stack'
import { Image } from 'expo-image'
import { useCallback, useMemo } from 'react'
import { StyleSheet } from 'react-native'
import { Appbar, Text } from 'react-native-paper'

import { Copies } from '../constants'

interface HeaderProps extends StackHeaderProps {
  children?: React.ReactNode
}

const styles = StyleSheet.create({
  image: {
    height: 40,
    width: 153,
  },
})

const Header = ({ navigation, route, options, children, back }: HeaderProps) => {
  // If the focused route is not found, we need to assume it's the initial screen
  // This can happen during if there hasn't been any navigation inside the screen
  const childRouteName = getFocusedRouteNameFromRoute(route) ?? 'Catalogues'
  const routeName = useMemo(
    () => (route.name === 'HomeTabs' ? childRouteName : route.name),
    [childRouteName, route.name],
  )
  const isCatalogues = useMemo(() => routeName === 'Catalogues', [routeName])
  const isCatalogueDetail = useMemo(() => routeName === 'CatalogueDetail', [routeName])

  const showBack = useMemo(
    // show back arrow when land directly to CatalogueDetail
    () => navigation.canGoBack() || (!navigation.canGoBack() && isCatalogueDetail),
    [isCatalogueDetail, navigation],
  )

  const headerTitle = useMemo(() => {
    switch (routeName) {
      case 'Geo':
        return Copies.your_location
      case 'ForYou':
        return Copies.for_you
      case 'Stores':
        return Copies.stores_near_you
      default:
        break
    }
  }, [routeName])

  const handleOnPressBack = useCallback(() => {
    navigation.canGoBack() && !isCatalogues
      ? navigation.goBack()
      : navigation.replace('HomeTabs', { screen: 'Catalogues', params: route.params })
  }, [isCatalogues, navigation, route.params])

  return (
    <Appbar.Header mode="center-aligned">
      {showBack && <Appbar.BackAction onPress={handleOnPressBack} />}
      <Appbar.Content
        title={
          isCatalogues ? (
            <Image
              priority="high"
              style={styles.image}
              contentFit="contain"
              alt={process.env.EXPO_PUBLIC_APP_NAME}
              // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
              source={require('../assets/images/logo.png')}
            />
          ) : typeof options.headerTitle === 'string' ? (
            <Text variant="labelLarge">{options.headerTitle}</Text>
          ) : (
            <Text variant="labelLarge">{headerTitle}</Text>
          )
        }
      />
      {children}
    </Appbar.Header>
  )
}

export default Header
