import { useCallback, useMemo } from 'react'
import { View } from 'react-native'
import createMapLink from 'react-native-open-maps'
import { Avatar, Card, IconButton, useTheme } from 'react-native-paper'

import { SpacingBase } from '../../constants'
import {
  deleteFavouriteStore,
  setFavouriteStore,
  useAppDispatch,
  useAppSelector,
} from '../../redux'
import type { Store } from '../../utils/api/types'
import { useStyles } from '../../utils/useStyles'
import RetailerDistance from '../RetailerDistance'

export interface StoreCardProps {
  id: Store['id']
  address: Store['address']
  city: Store['city']
  retailer: Store['retailer_name']
  distance: Store['_distance']
  flat?: boolean
}

export const StoreCard = ({ id, address, city, retailer, distance, flat }: StoreCardProps) => {
  const dispatch = useAppDispatch()
  const { favourite_stores: favouriteStores, location } = useAppSelector((state) => state.app)
  const isFav = useMemo(() => (id ? favouriteStores.includes(id) : false), [favouriteStores, id])
  const { colors } = useTheme()

  const styles = useStyles(
    ({ colors, roundness }) => ({
      cardContentStyle: {
        backgroundColor: flat ? colors.elevation.level0 : colors.elevation.level1,
        borderRadius: flat ? 0 : roundness * 3,
        borderWidth: flat ? 0 : 1,
        borderColor: colors.outlineVariant,
        flexDirection: 'row',
        padding: SpacingBase,
      },
      title: {
        paddingLeft: SpacingBase,
      },
      content: {
        paddingLeft: SpacingBase * 8,
      },
      avatar: {
        backgroundColor: colors.surfaceVariant,
        color: colors.onSurfaceVariant,
      },
    }),
    [flat],
  )

  const handleOnFavPress = useCallback(() => {
    isFav ? dispatch(deleteFavouriteStore(id!)) : dispatch(setFavouriteStore(id!))
  }, [dispatch, id, isFav])

  const handleOnDirectionsPress = useCallback(() => {
    if (address) {
      createMapLink({
        start: location.display,
        end: `${address}, ${city}`,
      })
    }
  }, [address, city, location.display])

  return (
    <Card elevation={0} contentStyle={styles.cardContentStyle}>
      <View style={{ flex: 1 }}>
        <Card.Title
          style={styles.title}
          left={() => <Avatar.Icon style={styles.avatar} size={SpacingBase * 5} icon="store" />}
          title={address}
          titleNumberOfLines={1}
          subtitleNumberOfLines={1}
          subtitle={city}
        />
        <Card.Content style={styles.content}>
          {retailer && <RetailerDistance retailer={retailer} distance={distance} />}
        </Card.Content>
      </View>
      <View>
        <IconButton
          onPress={handleOnFavPress}
          mode={isFav ? 'contained' : 'outlined'}
          icon={isFav ? 'star' : 'star-outline'}
          containerColor={isFav ? colors.primaryContainer : colors.surface}
          iconColor={isFav ? colors.onPrimaryContainer : colors.onSurface}
        />
        {address && (
          <IconButton mode="outlined" onPress={handleOnDirectionsPress} icon="directions" />
        )}
      </View>
    </Card>
  )
}

export default StoreCard
