import type { StackScreenProps } from '@react-navigation/stack'
import { useCallback } from 'react'
import { ErrorBoundary } from 'react-error-boundary'
import { StyleSheet, View } from 'react-native'
import { Text } from 'react-native-paper'

import ErrorFallback from '../components/ErrorFallback'
import { GeoLocationButton, GeoSearch } from '../components/Geo'
import { Copies, SpacingBase } from '../constants'
import type { RootStackParamList } from '../navigation/types'

export type GeoScreenProps = StackScreenProps<RootStackParamList, 'Geo', 'RootStack'>

const styles = StyleSheet.create({
  content: {
    paddingLeft: SpacingBase * 2,
    paddingRight: SpacingBase * 2,
  },
  input: {
    paddingLeft: SpacingBase * 2,
    paddingRight: SpacingBase * 2,
    marginBottom: SpacingBase,
  },
  divider: {
    marginTop: SpacingBase,
    marginBottom: SpacingBase,
    textAlign: 'center',
  },
})

const GeoScreen = ({ route, navigation }: GeoScreenProps) => {
  const handleOnResult = useCallback(() => {
    navigation.canGoBack()
      ? navigation.goBack()
      : navigation.navigate('HomeTabs', { screen: 'Catalogues', params: route.params })
  }, [navigation, route.params])

  return (
    <ErrorBoundary FallbackComponent={ErrorFallback}>
      <View style={styles.content}>
        <GeoLocationButton onLocationRetrieved={handleOnResult} />
        <Text style={styles.divider} variant="labelMedium">
          {Copies.or}
        </Text>
      </View>
      <GeoSearch inputContainerStyle={styles.input} onResultPress={handleOnResult} />
    </ErrorBoundary>
  )
}

export default GeoScreen
