import { useCallback } from 'react'
import type { ListRenderItem, ListRenderItemInfo } from 'react-native'
import { StyleSheet, FlatList, View, Platform } from 'react-native'

import CataloguesGridPlaceholder from './CataloguesGridPlaceholder'
import { SpacingBase } from '../../constants'
import { useAppSelector } from '../../redux'
import type { Catalogue } from '../../utils/api/types'
import useBreakpointsValue from '../../utils/useBreakpointsValue'
import { CatalogueCardAd } from '../CatalogueCard'
import { CataloguesListItem } from '../CataloguesList'

export interface CataloguesGridProps {
  catalogues: Catalogue[]
  ListHeaderComponent?: React.JSX.Element
}

const styles = StyleSheet.create({
  row: {
    paddingRight: SpacingBase * 2,
    marginBottom: SpacingBase * 2,
  },
  item: {
    flex: 1,
    marginLeft: SpacingBase * 2,
  },
})

export const CataloguesGrid = ({ catalogues, ListHeaderComponent }: CataloguesGridProps) => {
  const countryCode = useAppSelector((state) => state.app.countryCode)

  const numColumns =
    (useBreakpointsValue({ xs: 2, sm: 3, md: 4, lg: 5, xl: 6, xxl: 7 }) as number) || 2

  const handleRenderItem: ListRenderItem<Catalogue> = useCallback(
    ({ item, index }: ListRenderItemInfo<Catalogue>) => {
      return (
        <View style={styles.item}>
          <CataloguesListItem item={item} index={index} countryCode={countryCode} />
        </View>
      )
    },
    [countryCode],
  )

  const AdSeparator = ({ leadingItem }: { leadingItem: Catalogue[] }) => {
    return leadingItem[1]._hasAdNext ? <CatalogueCardAd /> : null
  }

  return (
    <FlatList
      numColumns={numColumns}
      key={numColumns}
      data={catalogues}
      renderItem={handleRenderItem}
      ListHeaderComponent={ListHeaderComponent}
      ListEmptyComponent={
        <CataloguesGridPlaceholder
          items={Array.from(
            { length: parseInt(process.env.EXPO_PUBLIC_CATALOGUES_LIST_LIMIT ?? '40', 10) },
            () => ({ _hasAdNext: true }),
          )}
        />
      }
      ItemSeparatorComponent={Platform.OS !== 'web' ? AdSeparator : undefined}
      columnWrapperStyle={styles.row}
      keyExtractor={(item) => item.id!}
    />
  )
}

export default CataloguesGrid
