import type { BottomTabScreenProps } from '@react-navigation/bottom-tabs'
import type { CompositeScreenProps } from '@react-navigation/native'
import type { StackScreenProps } from '@react-navigation/stack'
import { useCallback, useState } from 'react'
import { ErrorBoundary } from 'react-error-boundary'
import { StyleSheet, View } from 'react-native'

import { CataloguesGrid } from '../components/CataloguesGrid'
import ErrorFallback from '../components/ErrorFallback'
import { GeoAction } from '../components/Geo'
import { RetailersFilter } from '../components/RetailersFilter'
import { SpacingBase } from '../constants'
import type { HomeTabsParamList, RootStackParamList } from '../navigation/types'
import { useAppSelector } from '../redux'
import { useGetNearbyCataloguesWithAdsQuery } from '../utils/api'
import type { RetailerFilter } from '../utils/api/types'

export type CataloguesScreenProps = CompositeScreenProps<
  BottomTabScreenProps<HomeTabsParamList, 'Catalogues', 'HomeTabs'>,
  StackScreenProps<RootStackParamList>
>

const styles = StyleSheet.create({
  geoaction: {
    paddingLeft: SpacingBase * 2,
    paddingRight: SpacingBase * 2,
  },
})

const CataloguesScreen = ({ route, navigation }: CataloguesScreenProps) => {
  const { countryCode } = route.params
  const location = useAppSelector((state) => state.app.location)
  const {
    data = {
      catalogues: [],
      retailers: [],
    },
    error: cataloguesError,
  } = useGetNearbyCataloguesWithAdsQuery({
    countryCode,
    nearbyOptions: location,
  })
  const [filteredCatalogues, setFilteredCatalogues] = useState(data.catalogues)

  if (cataloguesError) {
    // TODO: handle error?
    throw new Error(JSON.stringify(cataloguesError))
  }

  const handleOnChange = useCallback(
    (retailers: RetailerFilter['id'][]) => {
      const newCatalogues = data.catalogues.filter((catalogue) =>
        retailers.some((id) => id === catalogue._retailer_id),
      )
      newCatalogues && setFilteredCatalogues(newCatalogues)
    },
    [data.catalogues],
  )

  return (
    <ErrorBoundary FallbackComponent={ErrorFallback}>
      <CataloguesGrid
        ListHeaderComponent={
          <>
            <View style={styles.geoaction}>
              <GeoAction />
            </View>
            <RetailersFilter retailers={data.retailers} onChange={handleOnChange} />
          </>
        }
        catalogues={filteredCatalogues.length > 0 ? filteredCatalogues : data.catalogues}
      />
    </ErrorBoundary>
  )
}

export default CataloguesScreen
