import { StatusBar } from 'expo-status-bar'
import { useEffect, useState } from 'react'
import { AppState } from 'react-native'
import { PaperProvider } from 'react-native-paper'

import { NavigationProvider, RootStack } from './navigation'
import {
  loadAndShowConsentFormIfRequired,
  setAppStatus,
  setStoredConsentAndChoices,
  useAppDispatch,
  useAppSelector,
} from './redux'
import { DarkTheme, LightTheme } from './utils/theme'

const AppContainer = () => {
  const dispatch = useAppDispatch()
  const theme = useAppSelector((state) => state.ui.theme)
  const { status: appStatus, user_onboard } = useAppSelector((state) => state.app)
  const consent_obtained = useAppSelector((state) => state.consent.consent_obtained)
  const [consentCheck, setConsentCheck] = useState(false)

  useEffect(() => {
    const initConsent = async () => {
      await dispatch(setStoredConsentAndChoices())
    }
    initConsent()
      .then(() => {
        setConsentCheck(true)
      })
      .catch((e) => {
        console.error(e)
      })
  }, [dispatch])

  useEffect(() => {
    const showConsentForm = async () => {
      await dispatch(loadAndShowConsentFormIfRequired())
    }
    if (consentCheck && !consent_obtained && user_onboard) {
      showConsentForm().catch((e) => {
        console.error(e)
      })
    }
  }, [consentCheck, consent_obtained, dispatch, user_onboard])

  useEffect(() => {
    const appStatusSubscription = AppState.addEventListener('change', (nextAppState) => {
      dispatch(setAppStatus(nextAppState))
    })
    return () => {
      appStatusSubscription.remove()
    }
  }, [appStatus, dispatch])

  return (
    <PaperProvider theme={theme === 'dark' ? DarkTheme : LightTheme}>
      <StatusBar style={theme === 'dark' ? 'light' : 'dark'} />
      <NavigationProvider theme={theme === 'dark' ? DarkTheme : LightTheme}>
        <RootStack />
      </NavigationProvider>
    </PaperProvider>
  )
}

export default AppContainer
